@font-face {
    font-family: 'Inter Variable';
    src: url('/fonts/Inter-roman.var.woff2') format('woff2-variations');
    font-weight: 100 900; /* Range of weights available */
    font-stretch: 25% 150%; /* Range of widths available */
    font-style: normal;
}

body {
    font-family: 'Inter Variable', sans-serif;
    /* Set default weight (wght) and slant (slnt) */
    font-variation-settings: "wght" 400, "slnt" 0;
}

h1 {
    /* Custom weight and negative slant for a distinct heading */
    font-variation-settings: "wght" 750, "slnt" -7;
    font-weight: 750; /* Fallback/hint for non-variable font support */
}

p.caption {
    /* Lighter weight, narrower width for captions */
    font-variation-settings: "wght" 300, "wdth" 85;
    font-weight: 300; /* Fallback/hint */
    font-stretch: 85%; /* Fallback/hint */
}
